SELECT COUNT(*)
FROM msg_subscription
WHERE deleted = FALSE

    AND user_id = #{userId}


    AND template_id = #{templateId}


    AND channel = #{channel}

SELECT ms.id, ms.user_id, u.username AS user_name, ms.template_id, mt.name AS template_name, ms.channel, ms.status, ms.preference, ms.created_time FROM msg_subscription ms LEFT JOIN sys_user u ON ms.user_id = u.id AND u.deleted = FALSE LEFT JOIN msg_template mt ON ms.template_id = mt.id AND mt.deleted = FALSE WHERE ms.deleted = FALSE
AND ms.user_id = #{query.userId}
AND ms.template_id = #{query.templateId}
AND ms.channel = #{query.channel}
AND ms.status = #{query.status}
ORDER BY ms.created_time DESC

SELECT COUNT(*)
FROM msg_subscription ms
WHERE ms.deleted = FALSE

    AND ms.user_id = #{query.userId}


    AND ms.template_id = #{query.templateId}


    AND ms.channel = #{query.channel}


    AND ms.status = #{query.status}
